/* Hearts and Minds witness layer — first-person evidence cards.
   One witness per moment. Every stat carries its source. Generated 12 Jun 2026. */
(function(){
var IMG = "Assets/Personas/";
var PERSONA = {"sarah": "HomeTest Operating Model - Persona Sarah.html", "priya": "HomeTest Operating Model - Persona Priya.html", "aisha": "HomeTest Operating Model - Persona Aisha.html", "adam": "HomeTest Operating Model - Persona Adam.html", "catherine": "HomeTest Operating Model - Persona Catherine.html", "joe": "HomeTest Operating Model - Persona Joe.html", "anita": "HomeTest Operating Model - Persona Anita.html", "hannah": "HomeTest Operating Model - Persona Hannah.html", "ngozi": "HomeTest Operating Model - Persona Ngozi.html", "david": "HomeTest Operating Model - Persona David.html"};
var M = {"abdul-a1": {"who": "Sarah", "role": "Commissioner", "img": "sarah", "say": "Somewhere out there are 4.2 million people, England-wide, with high blood pressure nobody has found. Abdul found his own — with his phone. That is a stroke I never have to commission.", "stat": "An estimated 4.2 million adults in England have undiagnosed high blood pressure; hypertension is implicated in around half of all heart attacks and strokes.", "source": "NHS England / Office for National Statistics, 2025", "url": "https://www.england.nhs.uk/north-west/2025/09/04/are-you-one-of-the-missing-millions-get-your-blood-pressure-checked-this-know-your-numbers-week/"}, "abdul-a2": {"who": "Sarah", "role": "Commissioner", "img": "sarah", "say": "Eight million outpatient appointments were missed last year, and I paid for every empty room. A kit waiting on his kitchen table cannot be missed — only posted a day late.", "stat": "8.0 million outpatient appointments in England went unattended in 2023/24, of 135.4 million booked. NHS England costs a missed outpatient appointment at around £120 — roughly £1bn a year of clinical time.", "source": "NHS Digital, Hospital Outpatient Activity 2023-24; NHS England DNA costings", "url": "https://digital.nhs.uk/data-and-information/publications/statistical/hospital-outpatient-activity/2023-24"}, "abdul-a3": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "Thirty-nine million people already carry the front door in their pocket. I don't have to build Abdul a platform — I have to plug the kit into the one he already uses.", "stat": "39 million people are registered on the NHS App, with 62.3 million logins in a single month.", "source": "NHS England, December 2025", "url": "https://www.england.nhs.uk/2025/12/record-numbers-using-nhs-app-to-manage-health/"}, "abdul-a4": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "Threshold alerts replace periodic reviews. My attention goes where the readings say — not where the diary says.", "stat": "Follow-up appointments account for 54% of NHS outpatient activity in England, much of it judged of limited clinical value.", "source": "GIRFT / NHS England outpatient improvement guide", "url": "https://gettingitrightfirsttime.co.uk/cross_cutting_theme/further-faster-programme/"}, "mark-a1": {"who": "Adam", "role": "Consultant urologist", "img": "adam", "say": "Prostate cancer is now the UK's most common cancer — more than sixty-four thousand men a year, and every one of them lands on a list like mine. The list grows. My clinic doesn't.", "stat": "64,000+ men diagnosed with prostate cancer in the UK per year (2022 data); around 6,500 a year choose active surveillance, with up to 5,000 more who could.", "source": "Prostate Cancer UK / NHS data, published 2025-26", "url": "https://prostatecanceruk.org/about-us/news-and-views/2026/01/prostate-most-common-cancer"}, "mark-a2": {"who": "Catherine", "role": "Acute Trust commissioner", "img": "catherine", "say": "Follow-ups are fifty-four per cent of everything my outpatient budget buys. Mark's routine PSA is precisely the kind of follow-up that never needed a room.", "stat": "Follow-up appointments represent 54% of NHS outpatient activity; standardised templates and remote models could unlock 1–2 million slots.", "source": "GIRFT, Further Faster programme", "url": "https://gettingitrightfirsttime.co.uk/cross_cutting_theme/further-faster-programme/"}, "mark-a3": {"who": "Joe", "role": "Supplier", "img": "joe", "say": "One and a quarter billion pathology requests this year, growing five and a half per cent annually. Buildings can't absorb that curve — kit out, post back, lab capacity where it's actually elastic.", "stat": "NHS pathology test requests projected at 1.25bn for 2025/26 (730m in 2013/14), growing ~5.5% a year.", "source": "NHS national programme analysis, 2026"}, "mark-a4": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "The silence is doing clinical work. Every result is reviewed in trend, and escalation happens when the line moves — safety is the review, not the appointment.", "stat": "England booked 135.4 million outpatient appointments in 2023/24; routine surveillance bloods need not be among them.", "source": "NHS Digital, Hospital Outpatient Activity 2023-24", "url": "https://digital.nhs.uk/data-and-information/publications/statistical/hospital-outpatient-activity/2023-24"}, "layla-a1": {"who": "Anita", "role": "ICB / GP commissioner", "img": "anita", "say": "Fifteen million missed GP-practice appointments a year — £216 million — and the system writes DNA as if it were her fault. Layla wasn't refusing care. She was keeping her job.", "stat": "Around 15 million general-practice appointments are missed each year, costing the NHS £216m (average ~£30 per missed GP appointment).", "source": "NHS England, 2019", "url": "https://www.england.nhs.uk/2019/01/missed-gp-appointments-costing-nhs-millions/"}, "layla-a2": {"who": "Hannah", "role": "GP", "img": "hannah", "say": "Iron-deficiency anaemia touches around eight per cent of adult women, and the monitoring is one blood tube on a six-month clock. The clock was never the problem. The clinic was.", "stat": "Iron deficiency anaemia prevalence in the UK is around 3% of adult men and 8% of adult women; guidelines monitor treatment response by FBC.", "source": "NICE clinical knowledge summary", "url": "https://cks.nice.org.uk/topics/anaemia-iron-deficiency/"}, "layla-a3": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "The result lands in her GP record, not in a silo — the same governance as any practice bloods. The kit changes the venue. It never changes the protections.", "stat": "DPIA, data-sharing and processing agreements are executed before go-live; the result flows to the GP record under the practice's existing controllership.", "source": "Service IG framework (executed pre-go-live)"}, "layla-a4": {"who": "Anita", "role": "ICB / GP commissioner", "img": "anita", "say": "Three hundred and seven million general-practice appointments a year, and one in twenty missed. Take even the routine bloods out of that queue and my access targets can finally breathe.", "stat": "~307 million general-practice sessions are scheduled annually in England; around 5% are missed without enough notice to rebook.", "source": "NHS England, 2019", "url": "https://www.england.nhs.uk/2019/01/missed-gp-appointments-costing-nhs-millions/"}, "sean-a1": {"who": "Hannah", "role": "GP", "img": "hannah", "say": "I run the annual health checks — uptake is nearly eighty per cent now. And still, people with a learning disability die a median nineteen and a half years younger than everyone else. The check exists because the gap is real. The bloods are where it stalls.", "stat": "79.9% of people on the learning disability register had an annual health check (March 2025); median age of death is 62.3 — about 19.5 years younger than the general population.", "source": "NHS England; LeDeR annual report 2023 (pub. 2025)", "url": "https://www.england.nhs.uk/learning-disabilities/improving-health/learning-from-lives-and-deaths/"}, "sean-a2": {"who": "His brother", "role": "Family", "img": null, "say": "Easy-read isn't a kindness we're asking for — it has been a legal duty since 2016. The Accessible Information Standard says information must work for the person it's about. For Sean, pictures work.", "stat": "The Accessible Information Standard has been a legal requirement for NHS and adult social care providers since 2016.", "source": "NHS England, Accessible Information Standard", "url": "https://www.england.nhs.uk/ourwork/accessibleinfo/"}, "sean-a3": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "The reasonable-adjustment flag exists nationally so Sean's needs travel with his record. Honouring it at the ordering step is the difference between a policy and a practice.", "stat": "The Reasonable Adjustment Digital Flag is a national NHS record flag enabling adjustments to be known across services.", "source": "NHS England, Reasonable Adjustment Digital Flag", "url": "https://www.england.nhs.uk/learning-disabilities/improving-health/reasonable-adjustments/"}, "sean-a4": {"who": "Sarah", "role": "Commissioner", "img": "sarah", "say": "Thirty-nine per cent of the deaths reviewed were judged avoidable. Avoidable is a commissioning word. Reach is the lever I hold — and this is what reach looks like.", "stat": "39% of reviewed deaths of people with a learning disability were assessed as avoidable (down from 46% in 2021).", "source": "LeDeR annual report 2023 (pub. 2025)", "url": "https://www.england.nhs.uk/learning-disabilities/improving-health/learning-from-lives-and-deaths/"}, "sarah-s1": {"who": "Sarah", "role": "LA sexual health commissioner", "img": "sarah", "say": "Around forty per cent of new HIV diagnoses in England still happen late, CD4 already collapsed, one-year mortality eight times the early-catch number. The wards my clinics struggle to reach are exactly where that forty per cent lives. The gap is not theoretical. It is a map.", "stat": "Late HIV diagnosis (CD4 <350) accounts for around 40% of new HIV diagnoses in England; one-year mortality after late diagnosis is around eight times higher than early diagnosis.", "source": "UKHSA, HIV in England Annual Report", "url": "https://www.gov.uk/government/publications/hiv-in-england-annual-report"}, "sarah-s2": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "Eighteen months and a clean-sheet procurement is the old price of standing up an HIV self-test service. The framework is the new price, call-off terms, admitted suppliers, templates ready. The price of entry is a signature, not a discovery exercise.", "stat": "Bespoke OJEU-compliant procurement of a new service typically takes 6-9 months at minimum; call-off against an inherited national framework (e.g. SBS Lot 1) typically completes in weeks.", "source": "NHS SBS framework guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "sarah-s3": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "Unsafe-address households, low digital literacy, language needs, these are not edge cases. They are the patients Sarah's cohort is defined by. The DPIA and the alternative pathways live in the inherited stack. The platform passes them through, it does not reinvent them.", "stat": "Around 1 in 6 adults in England have low digital literacy or are offline; the Reasonable Adjustment Digital Flag is a national NHS record flag enabling adjustments to be known across services.", "source": "ONS digital exclusion estimates; NHS England Reasonable Adjustment Digital Flag", "url": "https://www.england.nhs.uk/learning-disabilities/improving-health/reasonable-adjustments/"}, "sarah-s4": {"who": "Joe", "role": "Supplier", "img": "joe", "say": "Every LA that calls off saves me the bespoke contract negotiation I would otherwise run separately. The same DSA, the same DPIA, the same clinical safety case, written once nationally, executed many times locally. The supplier-side win is the same as the commissioner-side win.", "stat": "Per-supplier bespoke contracts historically take 3-6 months per LA to negotiate. Inherited framework templates remove most of this overhead.", "source": "NHS SBS framework guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "sarah-s5": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "The MI feed lands in her hands in real time. No annual return. No nine-month wait to find out the wards she targeted have not engaged. Thirty-nine million people on the NHS App is the data layer her cohort already lives in.", "stat": "39 million people are registered on the NHS App, with 62.3 million logins in a single month.", "source": "NHS England, December 2025", "url": "https://www.england.nhs.uk/2025/12/record-numbers-using-nhs-app-to-manage-health/"}, "sarah-s6": {"who": "Sarah", "role": "LA sexual health commissioner", "img": "sarah", "say": "Detection up, late diagnosis down, equity reach into the wards my clinics did not see, verified at ward level. The Board asked whether it worked. The numbers do most of the talking. The next year's ask is the next configuration, not the next procurement.", "stat": "England commits to ending new HIV transmissions by 2030; around 4,800 people in England are estimated to be living with undiagnosed HIV. Each HIV infection averted carries an estimated NHS lifetime cost of ~£320k.", "source": "UKHSA HIV Action Plan for England", "url": "https://www.gov.uk/government/publications/towards-zero-an-action-plan-towards-ending-hiv-transmission-aids-and-hiv-related-deaths-in-england-2022-to-2025/towards-zero-the-hiv-action-plan-for-england-2022-to-2025"}, "adam-s1": {"who": "Adam", "role": "Consultant urologist", "img": "adam", "say": "The patients I cannot see are the patients I lose. Prostate cancer is now the UK's most common cancer, more than sixty-four thousand men a year. The cohort grows. My clinic does not. The drop-outs are the ones I worry about most.", "stat": "64,000+ men diagnosed with prostate cancer in the UK per year (2022 data); around 6,500 a year choose active surveillance, with up to 5,000 more who could.", "source": "Prostate Cancer UK / NHS data, published 2025-26", "url": "https://prostatecanceruk.org/about-us/news-and-views/2026/01/prostate-most-common-cancer"}, "adam-s2": {"who": "Catherine", "role": "Acute Trust commissioner", "img": "catherine", "say": "Follow-ups are fifty-four per cent of everything my outpatient budget buys. Adam's quarterly PSA review is precisely the kind of follow-up that never needed a room. Eight million outpatient appointments went unattended last year, and I paid for every empty slot.", "stat": "Follow-up appointments represent 54% of NHS outpatient activity; 8.0m appointments in England went unattended in 2023/24; standardised templates and remote models could unlock 1-2 million slots.", "source": "GIRFT, Further Faster programme; NHS Digital Hospital Outpatient Activity 2023-24", "url": "https://gettingitrightfirsttime.co.uk/cross_cutting_theme/further-faster-programme/"}, "adam-s3": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "The clinical role is preserved because the result returns to Adam first, in trend, with threshold alerts wired to NICE NG131. The kit changes the venue. The clinical decision authority does not move. That is the safety case.", "stat": "NICE NG131 covers PSA testing thresholds and surveillance triggers; clinical safety case (DCB0129/0160) executed pre-go-live for the configuration.", "source": "NICE NG131; NHS Digital DCB0129 / DCB0160", "url": "https://www.nice.org.uk/guidance/ng131"}, "adam-s4": {"who": "Mark", "role": "His patient", "img": "mark", "say": "Adam asked me at the end of the appointment if I would be comfortable doing the next blood at home. I said yes before he finished the sentence. The kit arrived. I took the sample on the date the clinic would have happened. The next clinic appointment was the one I actually needed.", "stat": "Around 6,500 men a year currently choose active surveillance for prostate cancer in the UK; up to 5,000 more are eligible. Drop-out from surveillance is a recognised clinical problem.", "source": "Prostate Cancer UK; NICE NG131", "url": "https://prostatecanceruk.org/about-us/news-and-views/2026/01/prostate-most-common-cancer"}, "adam-s5": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "Adam's cohort dashboard exists because every result writes back to the EPR cleanly. Trends arrive in his inbox without a clerk in the loop. Thirty-nine million people already log into the NHS App; this is the data layer his cohort already lives in.", "stat": "39 million people are registered on the NHS App, with 62.3 million logins in a single month; result write-back to the Trust EPR is part of the inherited platform integration.", "source": "NHS England, December 2025", "url": "https://www.england.nhs.uk/2025/12/record-numbers-using-nhs-app-to-manage-health/"}, "adam-s6": {"who": "Adam", "role": "Consultant urologist", "img": "adam", "say": "More patients in surveillance. Fewer drop-outs. Same team. The clinic now holds the patients whose disease behaviour says clinic is the right venue. Pathology test volumes nationally are growing at five and a half per cent a year; the buildings cannot absorb that curve, but the cohort can stay safe anyway.", "stat": "NHS pathology test requests projected at 1.25bn for 2025/26 (730m in 2013/14), growing ~5.5% a year. Remote surveillance with threshold alerts is a proven mechanism for holding active surveillance cohorts without clinic-capacity penalty.", "source": "NHS national programme analysis, 2026; clinical practice patterns"}, "hannah-s1": {"who": "Hannah", "role": "GP partner", "img": "hannah", "say": "Iron-deficiency anaemia touches around eight per cent of adult women. The monitoring is one blood tube on a six-month clock. The clock was never the problem. The clinic was. The patients I lose are the ones the clinic was always going to lose.", "stat": "Iron deficiency anaemia prevalence in UK adult women is around 8%; routine monitoring is typically a 6-month FBC cycle.", "source": "NICE clinical knowledge summary; NHS guidance", "url": "https://cks.nice.org.uk/topics/anaemia-iron-deficiency/"}, "hannah-s2": {"who": "Anita", "role": "ICB / GP commissioner", "img": "anita", "say": "Fifteen million missed GP appointments a year. Two hundred and sixteen million pounds. The system writes DNA as if it were the patient&apos;s fault. They were keeping their job. The clinic was always the wrong venue for routine bloods.", "stat": "Around 15 million general-practice appointments are missed each year, costing the NHS £216m (average ~£30 per missed GP appointment).", "source": "NHS England, 2019", "url": "https://www.england.nhs.uk/2019/01/missed-gp-appointments-costing-nhs-millions/"}, "hannah-s3": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "The result writes back to the GP record under the practice&apos;s existing controllership. DPIA, data-sharing and processing agreements execute before go-live. The kit changes the venue. It does not change the protections.", "stat": "DPIA, DSA and DPA are executed pre-go-live; the home-test result flows to the GP record under the practice&apos;s existing controllership.", "source": "Service IG framework (executed pre-go-live)"}, "hannah-s4": {"who": "Layla", "role": "Hannah&apos;s patient", "img": "layla", "say": "Hannah asked me at the end of the appointment if I would be comfortable doing the next FBC at home. I said yes before she finished the sentence. The kit arrived. I took the sample on a Saturday. The next appointment was the one I actually needed.", "stat": "Around 8% of UK adult women have iron deficiency anaemia; routine FBC monitoring is the standard treatment-response measurement.", "source": "NICE clinical knowledge summary", "url": "https://cks.nice.org.uk/topics/anaemia-iron-deficiency/"}, "hannah-s5": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "The result rides the same rails as any other blood. Result back to the GP record, in trend, on time. No parallel system, no clerk in the loop. Thirty-nine million people are already on the NHS App; the patient does not see infrastructure, just the kit.", "stat": "39 million people are registered on the NHS App, with 62.3 million logins in a single month; result write-back to the GP record is via the framework&apos;s existing integration.", "source": "NHS England, December 2025", "url": "https://www.england.nhs.uk/2025/12/record-numbers-using-nhs-app-to-manage-health/"}, "hannah-s6": {"who": "Hannah", "role": "GP partner", "img": "hannah", "say": "Three hundred and seven million general-practice sessions a year. One in twenty missed. Take routine monitoring out of the queue and the access targets can finally breathe. The practice nurse is doing the work she should always have been doing.", "stat": "~307 million general-practice sessions are scheduled annually in England; around 5% are missed.", "source": "NHS England, 2019", "url": "https://www.england.nhs.uk/2019/01/missed-gp-appointments-costing-nhs-millions/"}, "abdul-s1": {"who": "Sarah", "role": "Commissioner", "img": "sarah", "say": "Somewhere out there are 4.2 million people, England-wide, with high blood pressure nobody has found. Abdul found his own with his phone. That is a stroke I never have to commission.", "stat": "An estimated 4.2 million adults in England have undiagnosed high blood pressure; hypertension is implicated in around half of all heart attacks and strokes.", "source": "NHS England / ONS, 2025", "url": "https://www.england.nhs.uk/north-west/2025/09/04/are-you-one-of-the-missing-millions-get-your-blood-pressure-checked-this-know-your-numbers-week/"}, "abdul-s2": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "Thirty-nine million people already carry the front door in their pocket. I don't have to build Abdul a platform. I have to plug the kit into the one he already uses.", "stat": "39 million people are registered on the NHS App, with 62.3 million logins in a single month.", "source": "NHS England, December 2025", "url": "https://www.england.nhs.uk/2025/12/record-numbers-using-nhs-app-to-manage-health/"}, "abdul-s3": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "Capillary lipid testing has been validated for years. The clinical question was never the science. It was the venue and the assurance chain. Both now sit in the framework.", "stat": "Capillary blood testing for lipid and HbA1c panels is validated under UKAS-accredited labs and CE-marked devices; routine monitoring is established practice.", "source": "UKAS ISO 15189; MHRA IVD framework"}, "abdul-s4": {"who": "Hannah", "role": "GP", "img": "hannah", "say": "When Abdul's result lands with me, the conversation is the same conversation. Lifestyle, statin if indicated, follow-up. The venue of the blood draw never changed the clinical decision.", "stat": "NICE CG181 sets prescribing thresholds for statin therapy in primary cardiovascular prevention; the clinical pathway is unchanged by home-test sampling.", "source": "NICE CG181", "url": "https://www.nice.org.uk/guidance/cg181"}, "abdul-s5": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "Threshold alerts replace periodic reviews. My attention goes where the readings say, not where the diary says.", "stat": "Follow-up appointments account for 54% of NHS outpatient activity in England, much of it judged of limited clinical value.", "source": "GIRFT / NHS England outpatient improvement guide", "url": "https://gettingitrightfirsttime.co.uk/cross_cutting_theme/further-faster-programme/"}, "mark-s1": {"who": "Adam", "role": "Consultant urologist", "img": "adam", "say": "Prostate cancer is now the UK's most common cancer, more than sixty-four thousand men a year, and every one of them lands on a list like mine. The list grows. My clinic does not.", "stat": "64,000+ men diagnosed with prostate cancer in the UK per year (2022 data); around 6,500 a year choose active surveillance, with up to 5,000 more who could.", "source": "Prostate Cancer UK / NHS data, 2025-26", "url": "https://prostatecanceruk.org/about-us/news-and-views/2026/01/prostate-most-common-cancer"}, "mark-s2": {"who": "Catherine", "role": "Acute Trust commissioner", "img": "catherine", "say": "Follow-ups are fifty-four per cent of everything my outpatient budget buys. Mark's routine PSA is precisely the kind of follow-up that never needed a room.", "stat": "Follow-up appointments represent 54% of NHS outpatient activity; standardised templates and remote models could unlock 1-2 million slots.", "source": "GIRFT, Further Faster programme", "url": "https://gettingitrightfirsttime.co.uk/cross_cutting_theme/further-faster-programme/"}, "mark-s3": {"who": "Joe", "role": "Supplier", "img": "joe", "say": "One and a quarter billion pathology requests this year, growing five and a half per cent annually. Buildings can't absorb that curve. Kit out, post back, lab capacity where it's actually elastic.", "stat": "NHS pathology test requests projected at 1.25bn for 2025/26 (730m in 2013/14), growing ~5.5% a year.", "source": "NHS national programme analysis, 2026"}, "mark-s4": {"who": "Adam", "role": "Consultant urologist", "img": "adam", "say": "The surveillance is the treatment. The clinical work is reading the trend. Mark's home result lands on my desk with everything that came before it, in the same review I would have run in clinic.", "stat": "NICE NG131 sets the active surveillance protocol; threshold breaches trigger MDT review and repeat imaging on a defined cycle.", "source": "NICE NG131", "url": "https://www.nice.org.uk/guidance/ng131"}, "mark-s5": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "The silence is doing clinical work. Every result is reviewed in trend, and escalation happens when the line moves. Safety is the review, not the appointment.", "stat": "England booked 135.4 million outpatient appointments in 2023/24; routine surveillance bloods need not be among them.", "source": "NHS Digital, Hospital Outpatient Activity 2023-24", "url": "https://digital.nhs.uk/data-and-information/publications/statistical/hospital-outpatient-activity/2023-24"}, "layla-s1": {"who": "Hannah", "role": "GP", "img": "hannah", "say": "Iron-deficiency anaemia touches around eight per cent of adult women. The monitoring is one blood tube on a six-month clock. The clock was never the problem. The clinic was.", "stat": "Iron deficiency anaemia prevalence in the UK is around 3% of adult men and 8% of adult women; guidelines monitor treatment response by FBC.", "source": "NICE clinical knowledge summary", "url": "https://cks.nice.org.uk/topics/anaemia-iron-deficiency/"}, "layla-s2": {"who": "Anita", "role": "ICB / GP commissioner", "img": "anita", "say": "Fifteen million missed GP-practice appointments a year, two hundred and sixteen million pounds, and the system writes DNA as if it were her fault. Layla wasn't refusing care. She was keeping her job.", "stat": "Around 15 million general-practice appointments are missed each year, costing the NHS £216m (average ~£30 per missed GP appointment).", "source": "NHS England, 2019", "url": "https://www.england.nhs.uk/2019/01/missed-gp-appointments-costing-nhs-millions/"}, "layla-s3": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "The result lands in her GP record, not in a silo, the same governance as any practice bloods. The kit changes the venue. It never changes the protections.", "stat": "DPIA, data-sharing and processing agreements are executed before go-live; the result flows to the GP record under the practice's existing controllership.", "source": "Service IG framework (executed pre-go-live)"}, "layla-s4": {"who": "Hannah", "role": "GP", "img": "hannah", "say": "Same prescription, same conversation, different venue for the blood. The treatment was always in primary care. The clinic was the friction, not the medicine.", "stat": "NICE guidelines on Iron deficiency anaemia treatment are unchanged by sample-venue; iron supplementation is titrated to FBC response.", "source": "NICE clinical knowledge summary", "url": "https://cks.nice.org.uk/topics/anaemia-iron-deficiency/"}, "layla-s5": {"who": "Anita", "role": "ICB / GP commissioner", "img": "anita", "say": "Three hundred and seven million general-practice appointments a year, and one in twenty missed. Take even the routine bloods out of that queue and my access targets can finally breathe.", "stat": "~307 million general-practice sessions are scheduled annually in England; around 5% are missed without enough notice to rebook.", "source": "NHS England, 2019", "url": "https://www.england.nhs.uk/2019/01/missed-gp-appointments-costing-nhs-millions/"}, "sean-s1": {"who": "Hannah", "role": "GP", "img": "hannah", "say": "I run the annual health checks, uptake is nearly eighty per cent now. And still, people with a learning disability die a median nineteen and a half years younger than everyone else. The check exists because the gap is real. The bloods are where it stalls.", "stat": "79.9% of people on the learning disability register had an annual health check (March 2025); median age of death is 62.3 years, about 19.5 years younger than the general population.", "source": "NHS England; LeDeR annual report 2023 (pub. 2025)", "url": "https://www.england.nhs.uk/learning-disabilities/improving-health/learning-from-lives-and-deaths/"}, "sean-s2": {"who": "His brother", "role": "Family", "img": null, "say": "Easy-read isn't a kindness we're asking for. It has been a legal duty since 2016. The Accessible Information Standard says information must work for the person it's about. For Sean, pictures work.", "stat": "The Accessible Information Standard has been a legal requirement for NHS and adult social care providers since 2016.", "source": "NHS England, Accessible Information Standard", "url": "https://www.england.nhs.uk/ourwork/accessibleinfo/"}, "sean-s3": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "The reasonable-adjustment flag exists nationally so Sean's needs travel with his record. Honouring it at the ordering step is the difference between a policy and a practice.", "stat": "The Reasonable Adjustment Digital Flag is a national NHS record flag enabling adjustments to be known across services.", "source": "NHS England, Reasonable Adjustment Digital Flag", "url": "https://www.england.nhs.uk/learning-disabilities/improving-health/reasonable-adjustments/"}, "sean-s4": {"who": "Hannah", "role": "GP", "img": "hannah", "say": "The treatment was never different for Sean. The wrap-around was. Easy-read prescribing, the support worker in the loop, the brother holding the calendar. That is what made the treatment actually take.", "stat": "Reasonable adjustments under the Equality Act 2010 require services to anticipate and meet the access needs of disabled patients across treatment as well as referral.", "source": "NHS England, Reasonable Adjustment Digital Flag; Equality Act 2010"}, "sean-s5": {"who": "Sarah", "role": "Commissioner", "img": "sarah", "say": "Thirty-nine per cent of the deaths reviewed were judged avoidable. Avoidable is a commissioning word. Reach is the lever I hold, and this is what reach looks like.", "stat": "39% of reviewed deaths of people with a learning disability were assessed as avoidable (down from 46% in 2021).", "source": "LeDeR annual report 2023 (pub. 2025)", "url": "https://www.england.nhs.uk/learning-disabilities/improving-health/learning-from-lives-and-deaths/"}, "joe-s2": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "Old price of bidding for NHS work was paying for the privilege of finding out what was wanted. New price is reading the criteria pack on Future NHS and deciding whether you fit. The door is open before you ask.", "stat": "The Procurement Act 2023 commenced 24 February 2024 and establishes streamlined dynamic-market routes for assured supplier admission; bespoke open-procedure procurement of a new service typically takes 6-9 months at minimum.", "source": "UK Government, PA23 guidance", "url": "https://www.gov.uk/government/collections/the-procurement-act-2023-guidance-documents"}, "joe-s3a": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "A structured EOI is a small commitment that does big reading. Same shape every time, same questions, same evidence references. We can compare suppliers fairly because we are reading the same form, not five different essays.", "stat": "Atamis is the NHS England-wide procurement platform; structured submissions on a common platform support consistent intake, evaluation and audit trail across NHS procurements.", "source": "NHS England Commercial / Atamis", "url": "https://www.atamis.co.uk/"}, "joe-s3b": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "Joe&apos;s submission lands in the same tenancy as every other admitted supplier. The evidence references attach to the artefact catalogue we already maintain. Nothing has to be invented to receive him. The rails were already there.", "stat": "Framework intake on a single procurement platform reduces variance in evaluation and creates a single audit trail per supplier across multiple call-offs.", "source": "NHS England Commercial / Atamis", "url": "https://www.atamis.co.uk/"}, "joe-s4a": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "The DPIA is one template. I review the pattern once, not five times because five LAs each want their own. The supplier inherits the template, the LA confirms its controllership, the protections are the same across every deployment.", "stat": "UK GDPR Article 35 requires a DPIA for processing likely to result in high risk; a single template executed centrally and inherited at LA-level removes duplicated assessment without weakening the protections.", "source": "UK GDPR Article 35; ICO DPIA guidance", "url": "https://ico.org.uk/for-organisations/uk-gdpr-guidance-and-resources/accountability-and-governance/data-protection-impact-assessments-dpias/"}, "joe-s4b": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "DCB0129 sits with the platform manufacturer and is portable across configurations once Joe&apos;s API is evidenced. DCB0160 sits with whoever operates the service locally. The framework pre-fabs the deployment artefacts so the local body amends and signs the local context, instead of authoring the safety case from scratch.", "stat": "DCB0129 (manufacturer clinical risk management) sits with the platform manufacturer. DCB0160 (deployment safety) sits with the operating organisation (LA, Trust or supplier-as-managed-service depending on local arrangement). Centre-led artefact pre-fab is the agreed scaling pattern.", "source": "NHS Digital DCB0129 / DCB0160", "url": "https://digital.nhs.uk/services/clinical-safety"}, "joe-s4c": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "The conformance certificate is the contract carrier. Every commissioner calling Joe off reads the same evidence pack, signs the same call-off, runs the same terms. Three months of bilateral legal negotiation per LA disappears. That is the saving the framework is meant to deliver.", "stat": "Inherited framework call-off mechanisms typically reduce contract-to-service-launch timing from 6-9 months bespoke to a matter of weeks per call-off.", "source": "NHS SBS framework call-off guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "joe-s4d": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "Joe integrates once to the platform. That integration sits at API-level. Every test he adds under it is a configuration, not a build. Every commissioner he serves through it inherits the same rails. The platform is the singular asset the framework rests on.", "stat": "Single-API integration with downstream configuration variance is the modern NHS platform pattern (e.g. NHS App, EPS); per-test bespoke integration is the legacy alternative.", "source": "NHS Digital architecture patterns / API catalogue", "url": "https://digital.nhs.uk/developer/api-catalogue"}, "joe-s5": {"who": "Sarah", "role": "LA sexual health commissioner", "img": "sarah", "say": "My job is to commission the service for my cohort. It is not to re-assure that a framework-admitted supplier is safe. The conformance certificate is the trust marker. My first question to Joe was when can we go live, not whether we should.", "stat": "Late HIV diagnosis (CD4 <350) accounts for around 40% of new HIV diagnoses in England; commissioning speed is one of the levers that closes the gap.", "source": "UKHSA, HIV in England Annual Report", "url": "https://www.gov.uk/government/publications/hiv-in-england-annual-report"}, "joe-s6a": {"who": "Ngozi", "role": "Information Governance", "img": "ngozi", "say": "Joe is reused across three conditions and six commissioners without a fresh DPIA at each step. The annual refresh is when I look again, not every call-off. That is what onboard-once means in practice from where I sit.", "stat": "DPIA review is required where processing materially changes; an annual refresh cycle aligns with ICO guidance for stable processing activities.", "source": "ICO DPIA guidance", "url": "https://ico.org.uk/for-organisations/uk-gdpr-guidance-and-resources/accountability-and-governance/data-protection-impact-assessments-dpias/"}, "joe-s6b": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "Each new commissioner calling Joe off is a call-off, not a tender. The framework holds the standing terms. The deployment is the business. That is the unit economics the framework was designed to unlock for smaller suppliers.", "stat": "Framework call-off mechanisms reduce per-deployment legal and assurance cost to a small fraction of bespoke procurement, supporting market participation by smaller suppliers.", "source": "NHS SBS framework guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "catherine-s1": {"who": "Adam", "role": "Consultant urologist", "img": "adam", "say": "Prostate cancer is the UK's most common cancer now, more than sixty-four thousand men a year, and the active-surveillance cohort only grows. Catherine's monitoring caseload is real men on my lists. The clinic cannot hold all of them in a room.", "stat": "64,000+ men are diagnosed with prostate cancer in the UK each year (2022 data); around 6,500 a year choose active surveillance, with up to 5,000 more who could.", "source": "Prostate Cancer UK / NHS data, 2025-26", "url": "https://prostatecanceruk.org/about-us/news-and-views/2026/01/prostate-most-common-cancer"}, "catherine-s2": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "The old price of standing up a monitoring pathway was a clean-sheet procurement. Catherine opens an admitted framework instead. Suppliers listed, call-off terms published, safety-case and IG templates ready. The price of entry is a signature, not a discovery exercise.", "stat": "Bespoke open-procedure procurement of a new service typically takes 6-9 months at minimum; call-off against an inherited national framework typically completes in weeks.", "source": "NHS SBS framework guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "catherine-s3": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "The clinical authority does not move. Capillary PSA returns to the consultant urologist first, in trend, with thresholds wired to NICE NG131, and the clinical safety case is executed before go-live. The kit changes the venue of the blood, not the decision.", "stat": "NICE NG131 covers PSA testing thresholds and active-surveillance triggers; the clinical safety case (DCB0129 / DCB0160) is executed pre-go-live for the configuration.", "source": "NICE NG131; NHS Digital DCB0129 / DCB0160", "url": "https://www.nice.org.uk/guidance/ng131"}, "catherine-s4": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "An ICB mandate route into her Trust partners, not an external tender. Six weeks from brief to first live Trust, payment on published call-off terms. The procurement scar she carried in is not the arrangement she signed.", "stat": "Inherited framework call-off mechanisms typically reduce contract-to-service-launch timing from 6-9 months bespoke to a matter of weeks per call-off.", "source": "NHS SBS framework call-off guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "catherine-s5": {"who": "Adam", "role": "Consultant urologist", "img": "adam", "say": "The surveillance is the treatment and the clinical work is reading the trend. Follow-ups are more than half of everything the outpatient budget buys, and a routine PSA is exactly the follow-up that never needed a room. My clinic now holds the patients whose disease behaviour says clinic is the right venue.", "stat": "Follow-up appointments account for 54% of NHS outpatient activity in England; 8.0 million appointments went unattended in 2023/24, of 135.4 million booked.", "source": "GIRFT / NHS England outpatient improvement guide; NHS Digital Hospital Outpatient Activity 2023-24", "url": "https://gettingitrightfirsttime.co.uk/cross_cutting_theme/further-faster-programme/"}, "catherine-s6": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "What the CMO sees is one MI feed and one cohort view, because the integration happened once, nationally. Catherine's Trusts did not each build a special interface. Her men walked in through a front door thirty-nine million people already use.", "stat": "39 million people are registered on the NHS App, with 62.3 million logins in a single month; result write-back to the Trust EPR is part of the inherited platform integration.", "source": "NHS England, December 2025", "url": "https://www.england.nhs.uk/2025/12/record-numbers-using-nhs-app-to-manage-health/"}, "anita-s1": {"who": "Hannah", "role": "GP partner", "img": "hannah", "say": "Anita's at-risk register runs into the tens of thousands, and it keeps growing. More than three and a half million people now sit on GP non-diabetic-hyperglycaemia registers in England, up almost a fifth in a year. The ones the register serves worst are the ones who cannot get to the clinic.", "stat": "3,615,330 people were recorded with non-diabetic hyperglycaemia on GP registers in England in 2023, up 18% on 2022; around 1 in 9 adults in England are affected.", "source": "National Diabetes Audit / Diabetes UK, 2024", "url": "https://www.diabetes.org.uk/about-us/news-and-views/one-five-adults-now-live-diabetes-or-prediabetes-uk"}, "anita-s2": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "Anita opens an admitted framework, not a clean-sheet procurement. The HbA1c configuration is live, suppliers are listed on published call-off terms, and the QOF-linkage templates are ready. Her question is which configuration, not which procurement.", "stat": "Bespoke open-procedure procurement of a new service typically takes 6-9 months at minimum; call-off against an inherited national framework typically completes in weeks.", "source": "NHS SBS framework guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "anita-s3": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "Capillary HbA1c is held to DCCT-aligned analytical performance, the same standard as the practice's venous samples. Forty-two to forty-seven flags non-diabetic hyperglycaemia; forty-eight on a repeat confirms diabetes. The decision thresholds do not move because the sample came from a kitchen table.", "stat": "HbA1c of 42-47 mmol/mol identifies non-diabetic hyperglycaemia; 48 mmol/mol (6.5%) or above on a repeat sample confirms type 2 diabetes.", "source": "WHO 2011 HbA1c diagnostic criteria, adopted by NICE"}, "anita-s4": {"who": "David", "role": "NHS Commercial", "img": "david", "say": "One call-off, every practice in the ICB plugging into a common schedule, QOF-linked where it applies. Six weeks from brief to first live practice, not eighteen months. That is what the framework is for.", "stat": "Inherited framework call-off mechanisms typically reduce contract-to-service-launch timing from 6-9 months bespoke to a matter of weeks per call-off.", "source": "NHS SBS framework call-off guidance (timing reflects commercial-experience baseline; specific durations not published on the SBS frameworks page)"}, "anita-s5": {"who": "Priya", "role": "NHSE Platform", "img": "priya", "say": "The result rides the same rails as any other blood: back to the GP record, in trend, with QOF DM006 auto-linkage. No parallel system, no clerk in the loop. Thirty-nine million people are already on the NHS App; the patient just sees the kit.", "stat": "39 million people are registered on the NHS App, with 62.3 million logins in a single month; result write-back to the GP record is via the framework's existing integration.", "source": "NHS England, December 2025", "url": "https://www.england.nhs.uk/2025/12/record-numbers-using-nhs-app-to-manage-health/"}, "anita-s6": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "The prevention pathway works when you can keep the at-risk cohort in view. The NHS Diabetes Prevention Programme cut type 2 incidence by more than a third in the people who completed it. Home HbA1c is how you find the drift early enough to refer them in time.", "stat": "An independent evaluation of the NHS Diabetes Prevention Programme found a 37% relative reduction in type 2 diabetes incidence among completers and a 7% reduction at population level.", "source": "DIPLOMA evaluation; NHS England Diabetes high impact interventions", "url": "https://www.england.nhs.uk/ourwork/prevention/secondary-prevention/diabetes-high-impact-interventions/"}, "devi-s1": {"who": "Hannah", "role": "GP partner", "img": "hannah", "say": "The cohort I lose is the cohort most at risk. Black and South Asian patients are two to four times more likely to develop type 2 diabetes, and it starts younger, from around twenty-five. Devi is exactly who the register is for, and exactly who a mid-week clinic slot fails.", "stat": "Black and South Asian people are two to four times more likely to develop type 2 diabetes than White people; risk rises from around age 25 rather than 40.", "source": "Diabetes UK", "url": "https://www.diabetes.org.uk/about-diabetes/type-2-diabetes/diabetes-ethnicity"}, "devi-s2": {"who": "Anita", "role": "ICB / GP commissioner", "img": "anita", "say": "Fifteen million missed general-practice appointments a year, two hundred and sixteen million pounds, and the system records DNA as if it were her fault. Devi was not refusing care. She was keeping her job. The flag on her record is a venue problem, not a compliance problem.", "stat": "Around 15 million general-practice appointments are missed each year, costing the NHS £216m (average ~£30 per missed GP appointment).", "source": "NHS England, 2019", "url": "https://www.england.nhs.uk/2019/01/missed-gp-appointments-costing-nhs-millions/"}, "devi-s3": {"who": "Aisha", "role": "Clinical / CSG", "img": "aisha", "say": "The Saturday-morning sample is held to the same DCCT-aligned standard as the practice's venous bloods. The result lands in Hannah's system in time for the review the clinic would have run. The science was never the barrier. The venue was.", "stat": "Capillary HbA1c on a DCCT-aligned assay platform is held to the same analytical performance standard as venous samples; HbA1c is the established measure for glycaemic surveillance.", "source": "WHO 2011 HbA1c diagnostic criteria, adopted by NICE; IFCC standardisation"}, "devi-s4": {"who": "Hannah", "role": "GP partner", "img": "hannah", "say": "At forty-four the plan stands and the next review is twelve months out. A drift into the mid-forties is when I want the conversation and a prevention-programme referral, and the evidence says that referral matters: completers cut their diabetes risk by more than a third. The home result is what lets me catch the drift in time.", "stat": "The NHS Diabetes Prevention Programme achieved a 37% relative reduction in type 2 diabetes incidence among completers; referral is triggered by HbA1c in the non-diabetic hyperglycaemia range (42-47 mmol/mol).", "source": "DIPLOMA evaluation; NHS England Diabetes high impact interventions", "url": "https://www.england.nhs.uk/ourwork/prevention/secondary-prevention/diabetes-high-impact-interventions/"}, "devi-s5": {"who": "Anita", "role": "ICB / GP commissioner", "img": "anita", "say": "Devi stays in the cycle, and that is the whole point. Of the first hundred thousand people referred to the prevention programme, only just over half attended the first assessment. The ones who fall out are the ones the clinic was always going to lose. Home testing is how you hold the cohort the system quietly drops.", "stat": "Of the first 100,000 referrals to the NHS Diabetes Prevention Programme from primary care, just over half attended the initial assessment.", "source": "NHS Diabetes Prevention Programme uptake evaluation", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC10091609/"}};
var css = ".hm-witness{position:relative;display:inline-block;vertical-align:middle;margin-left:10px;}"+
".hmw-chip{width:38px;height:38px;border-radius:50%;border:2.5px solid #FFB91D;background:#fff;cursor:pointer;padding:0;overflow:hidden;box-shadow:0 3px 10px rgba(0,32,64,0.22);display:inline-flex;align-items:center;justify-content:center;transition:transform .15s ease;}"+
".hmw-chip:hover{transform:scale(1.12);}"+
".hmw-chip img{width:100%;height:100%;object-fit:cover;object-position:top center;display:block;}"+
".hmw-chip .hmw-init{font:800 15px 'Segoe UI',sans-serif;color:#003087;}"+
".hmw-card{position:absolute;top:46px;left:50%;transform:translateX(-50%);width:330px;max-width:82vw;background:#fff;border:1px solid #d6e2ef;border-top:4px solid #FFB91D;border-radius:12px;box-shadow:0 16px 40px rgba(0,32,64,0.25);padding:16px 18px;z-index:500;display:none;text-align:left;}"+
".hm-witness.open .hmw-card,.hm-witness:hover .hmw-card{display:block;}"+
".hmw-head{display:flex;align-items:center;gap:10px;margin-bottom:9px;}"+
".hmw-head img{width:34px;height:34px;border-radius:50%;object-fit:cover;object-position:top center;}"+
".hmw-name{font:800 13px 'Segoe UI',sans-serif;color:#003087;}"+
".hmw-role{font:700 9px 'Segoe UI',sans-serif;color:#7E8B97;letter-spacing:1px;text-transform:uppercase;}"+
".hmw-say{font:italic 600 13px 'Segoe UI',sans-serif;color:#212B32;line-height:1.5;margin-bottom:9px;}"+
".hmw-stat{font:600 11.5px 'Segoe UI',sans-serif;color:#4C6272;line-height:1.5;background:#F4F8FC;border-left:3px solid #005EB8;padding:8px 10px;border-radius:0 8px 8px 0;margin-bottom:8px;}"+
".hmw-src{font:600 9px 'Segoe UI',sans-serif;color:#7E8B97;letter-spacing:0.4px;}"+
".hmw-link{display:inline-block;margin-top:7px;font:800 10.5px 'Segoe UI',sans-serif;color:#005EB8;text-decoration:none;}";
var st = document.createElement("style"); st.textContent = css; document.head.appendChild(st);
document.querySelectorAll(".hm-witness[data-moment]").forEach(function(el){
  var m = M[el.getAttribute("data-moment")]; if(!m) return;
  var chip = document.createElement("button"); chip.className = "hmw-chip";
  chip.setAttribute("aria-label", m.who + " — their view of this moment");
  chip.innerHTML = m.img ? '<img src="' + IMG + m.img + '.png" alt="' + m.who + '">' : '<span class="hmw-init">' + m.who.charAt(0) + '</span>';
  if (m.img) { var ci = chip.querySelector("img"); ci.addEventListener("error", function(){ chip.innerHTML = '<span class="hmw-init">' + m.who.charAt(0) + "</span>"; }); }
  var card = document.createElement("div"); card.className = "hmw-card";
  var link = (m.img && PERSONA[m.img]) ? '<a class="hmw-link" href="' + PERSONA[m.img] + '">' + m.who + "&rsquo;s page &rarr;</a>" : "";
  card.innerHTML = '<div class="hmw-head">' + (m.img ? '<img src="' + IMG + m.img + '.png" alt="" onerror="this.remove()">' : "") +
    '<div><div class="hmw-name">' + m.who + '</div><div class="hmw-role">' + m.role + "</div></div></div>" +
    '<div class="hmw-say">&ldquo;' + m.say + '&rdquo;</div>' +
    '<div class="hmw-stat">' + m.stat + '</div>' +
    '<div class="hmw-src">Source: ' + (m.url ? '<a href="' + m.url + '" target="_blank" rel="noopener" style="color:#005EB8;text-decoration:underline;">' + m.source + "</a>" : m.source) + "</div>" + link;
  el.appendChild(chip); el.appendChild(card);
  function positionCard(){
    card.style.left = "50%"; card.style.right = "auto"; card.style.transform = "translateX(-50%)";
    var prevDisplay = card.style.display, prevVis = card.style.visibility;
    if (window.getComputedStyle(card).display === "none") { card.style.visibility = "hidden"; card.style.display = "block"; }
    var rect = card.getBoundingClientRect();
    var vw = document.documentElement.clientWidth;
    // Find the nearest container to bound against (the white .page box on Journey pages)
    var container = el.closest(".page, .stage-main, .stage, main, article") || document.body;
    var crect = container.getBoundingClientRect();
    var rightLimit = Math.min(vw - 20, crect.right - 20);
    var leftLimit = Math.max(20, crect.left + 20);
    if (rect.right > rightLimit) { card.style.left = "auto"; card.style.right = "0"; card.style.transform = "none"; }
    else if (rect.left < leftLimit) { card.style.left = "0"; card.style.transform = "none"; }
    card.style.display = prevDisplay; card.style.visibility = prevVis;
  }
  el.addEventListener("mouseenter", positionCard);
  chip.addEventListener("focus", positionCard);
  chip.addEventListener("click", function(e){ e.stopPropagation(); e.preventDefault();
    positionCard();
    document.querySelectorAll(".hm-witness.open").forEach(function(o){ if(o!==el) o.classList.remove("open"); });
    el.classList.toggle("open"); });
});
document.addEventListener("click", function(){ document.querySelectorAll(".hm-witness.open").forEach(function(o){ o.classList.remove("open"); }); });
})();
